import json
import os
from typing import Any, Dict, List, Union, Type
from pathlib import Path


class UserPreferences:
    """Base class for custom preference objects that can be serialized"""
    
    def to_dict(self) -> Dict[str, Any]:
        """Convert object to dictionary for serialization"""
        return {k: v for k, v in self.__dict__.items() if not k.startswith('_')}
    
    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> 'UserPreferences':
        """Create object from dictionary"""
        obj = cls()
        for key, value in data.items():
            setattr(obj, key, value)
        return obj


class PreferenceValidator:
    """Validates preference data structure and types"""
    
    ALLOWED_TYPES = (str, int, float, bool, type(None), dict, list)
    
    @staticmethod
    def validate_structure(data: Any, max_depth: int = 10, current_depth: int = 0) -> bool:
        """Validate that data only contains allowed types and doesn't exceed max depth"""
        if current_depth > max_depth:
            raise ValueError(f"Data structure exceeds maximum depth of {max_depth}")
        
        if isinstance(data, dict):
            for key, value in data.items():
                if not isinstance(key, str):
                    raise TypeError(f"Dictionary keys must be strings, got {type(key)}")
                PreferenceValidator.validate_structure(value, max_depth, current_depth + 1)
        elif isinstance(data, list):
            for item in data:
                PreferenceValidator.validate_structure(item, max_depth, current_depth + 1)
        elif not isinstance(data, PreferenceValidator.ALLOWED_TYPES):
            raise TypeError(f"Invalid type {type(data)} found in preferences")
        
        return True
    
    @staticmethod
    def validate_schema(data: Any, schema: Dict[str, Type]) -> bool:
        """Validate data against expected schema"""
        if not isinstance(data, dict):
            raise TypeError("Root preferences must be a dictionary")
        
        for key, expected_type in schema.items():
            if key in data:
                value = data[key]
                if expected_type == Any:
                    continue
                if not isinstance(value, expected_type):
                    raise TypeError(f"Expected {expected_type} for key '{key}', got {type(value)}")
        
        return True


class PreferenceSerializer:
    """Handles serialization of complex objects to JSON-compatible format"""
    
    @staticmethod
    def serialize(obj: Any) -> Any:
        """Convert complex objects to JSON-serializable format"""
        if isinstance(obj, UserPreferences):
            return {
                '__type__': obj.__class__.__name__,
                '__module__': obj.__class__.__module__,
                'data': obj.to_dict()
            }
        elif isinstance(obj, dict):
            return {k: PreferenceSerializer.serialize(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [PreferenceSerializer.serialize(item) for item in obj]
        elif isinstance(obj, (str, int, float, bool, type(None))):
            return obj
        else:
            raise TypeError(f"Cannot serialize type {type(obj)}")
    
    @staticmethod
    def deserialize(data: Any, custom_classes: Dict[str, Type] = None) -> Any:
        """Convert JSON data back to complex objects"""
        custom_classes = custom_classes or {}
        
        if isinstance(data, dict):
            if '__type__' in data and '__module__' in data:
                class_name = data['__type__']
                if class_name in custom_classes:
                    cls = custom_classes[class_name]
                    return cls.from_dict(PreferenceSerializer.deserialize(data['data'], custom_classes))
                else:
                    return data['data']
            else:
                return {k: PreferenceSerializer.deserialize(v, custom_classes) for k, v in data.items()}
        elif isinstance(data, list):
            return [PreferenceSerializer.deserialize(item, custom_classes) for item in data]
        else:
            return data


def save_preferences(preferences: Dict[str, Any], filepath: Union[str, Path], 
                    validate: bool = True, indent: int = 2) -> None:
    """
    Save user preferences to a JSON file
    
    Args:
        preferences: Dictionary containing user preferences
        filepath: Path to save the preferences file
        validate: Whether to validate the structure before saving
        indent: JSON indentation level (None for compact format)
    """
    filepath = Path(filepath)
    
    if validate:
        PreferenceValidator.validate_structure(preferences)
    
    serialized = PreferenceSerializer.serialize(preferences)
    
    filepath.parent.mkdir(parents=True, exist_ok=True)
    
    temp_filepath = filepath.with_suffix('.tmp')
    
    try:
        with open(temp_filepath, 'w', encoding='utf-8') as f:
            json.dump(serialized, f, indent=indent, ensure_ascii=False)
        
        temp_filepath.replace(filepath)
    except Exception as e:
        if temp_filepath.exists():
            temp_filepath.unlink()
        raise e


def load_preferences(filepath: Union[str, Path], 
                    custom_classes: Dict[str, Type] = None,
                    schema: Dict[str, Type] = None,
                    validate: bool = True,
                    max_size_mb: int = 10) -> Dict[str, Any]:
    """
    Load user preferences from a JSON file
    
    Args:
        filepath: Path to the preferences file
        custom_classes: Dictionary mapping class names to class types for deserialization
        schema: Optional schema to validate against
        validate: Whether to validate the loaded structure
        max_size_mb: Maximum file size in MB to prevent loading huge files
    
    Returns:
        Dictionary containing user preferences
    """
    filepath = Path(filepath)
    
    if not filepath.exists():
        raise FileNotFoundError(f"Preferences file not found: {filepath}")
    
    file_size_mb = filepath.stat().st_size / (1024 * 1024)
    if file_size_mb > max_size_mb:
        raise ValueError(f"Preferences file too large: {file_size_mb:.2f}MB (max: {max_size_mb}MB)")
    
    with open(filepath, 'r', encoding='utf-8') as f:
        data = json.load(f)
    
    if validate:
        PreferenceValidator.validate_structure(data)
    
    if schema:
        PreferenceValidator.validate_schema(data, schema)
    
    preferences = PreferenceSerializer.deserialize(data, custom_classes)
    
    return preferences


