def merge_preferences(defaults: Dict[str, Any], loaded: Dict[str, Any]) -> Dict[str, Any]:
    """Merge loaded preferences with defaults, preserving structure"""
    result = defaults.copy()
    
    for key, value in loaded.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key] = merge_preferences(result[key], value)
        else:
            result[key] = value
    
    return result